{"file_path":"/home/user/workspace/lib/db.js","content":"// In-memory product store — simulates a database that gets refreshed
// from upstream ERP/PIM systems during a catalog sync.
let products = [
  { id: 1, name: 'Laptop', price: 999, inStock: true, updatedAt: null },
  { id: 2, name: 'Phone', price: 699, inStock: true, updatedAt: null },
  { id: 3, name: 'Tablet', price: 499, inStock: false, updatedAt: null },
  { id: 4, name: 'Headphones', price: 199, inStock: true, updatedAt: null },
  { id: 5, name: 'Watch', price: 299, inStock: true, updatedAt: null },
];

/**
 * Returns a snapshot of the current product catalog.
 * Simulates a 100 ms database read delay.
 */
export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));
  return products.map((p) => ({ ...p }));
}

/**
 * Simulates a long-running sync from an upstream ERP/PIM system.
 * Updates prices, availability, and the sync timestamp to mimic
 * real data that changes between refresh cycles.
 *
 * In production this would call external APIs, transform data, and
 * write to a primary database — the read cache is invalidated
 * separately via revalidateTag("products").
 */
export async function syncProducts() {
  // Simulate upstream fetch / transform time
  await new Promise((resolve) => setTimeout(resolve, 4000));

  const now = new Date().toISOString();

  products = products.map((p) => ({
    ...p,
    price: Math.round((p.price + (Math.random() - 0.5) * 60)) || 1,
    inStock: Math.random() > 0.2,
    updatedAt: now,
  }));

  console.log('[Sync] Catalog sync completed at', now);
}
"}

